   127→			eval = EvalPermission(action, fmt.Sprintf("%s:%s:%s", opts.Resource, opts.Attr, req.Name))
   128→		}
   129→	} else if req.Verb == utils.VerbList || req.Verb == utils.VerbCreate {
   130→		// For list request we need to filter out in storage layer.
   131→		// For create requests we don't have a name yet, so we can only check if the action is allowed.
   132→		eval = EvalPermission(action)
   133→	} else {
   134→		// Assuming that all non list request should have a valid name
   135→		return claims.CheckResponse{}, fmt.Errorf("unhandled authorization: %s %s", req.Group, req.Verb)
   136→	}
